import React, { useEffect, useState } from 'react';
import axios from 'axios';

const statusColor = { pending: '#f39c12', approved: '#27ae60', rejected: '#e74c3c', expired: '#95a5a6' };

const s = {
  page: { padding: 32, maxWidth: 900, margin: '0 auto' },
  title: { fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 24 },
  card: { background: '#fff', borderRadius: 14, padding: '24px', marginBottom: 16, boxShadow: '0 2px 12px rgba(0,0,0,0.07)', display: 'grid', gridTemplateColumns: '1fr auto', gap: 16, alignItems: 'center' },
  passNum: { fontSize: 13, color: '#888', marginBottom: 4 },
  route: { fontSize: 18, fontWeight: 700, color: '#1a3a5c', marginBottom: 6 },
  meta: { fontSize: 13, color: '#666', display: 'flex', gap: 20, flexWrap: 'wrap' },
  badge: { padding: '4px 14px', borderRadius: 20, fontSize: 13, fontWeight: 700 },
  renewBtn: { padding: '8px 20px', background: '#2980b9', color: '#fff', border: 'none', borderRadius: 8, cursor: 'pointer', fontSize: 14, fontWeight: 600 },
  remarks: { fontSize: 12, color: '#e74c3c', marginTop: 4 },
  empty: { textAlign: 'center', color: '#aaa', fontSize: 16, marginTop: 60 }
};

export default function MyPasses() {
  const [passes, setPasses] = useState([]);
  const [loading, setLoading] = useState(true);

  const load = () => {
    setLoading(true);
    axios.get('/api/pass/my').then(r => { setPasses(r.data); setLoading(false); });
  };

  useEffect(load, []);

  const renew = async (id) => {
    await axios.post(`/api/pass/renew/${id}`, { passType: 'monthly' });
    load();
  };

  if (loading) return <div style={{ textAlign: 'center', marginTop: 60, color: '#888' }}>Loading...</div>;

  return (
    <div style={s.page}>
      <div style={s.title}>🎫 My Bus Passes</div>
      {passes.length === 0 && <div style={s.empty}>No pass applications yet.<br />Go to "Apply Pass" to get started.</div>}
      {passes.map(p => (
        <div key={p._id} style={s.card}>
          <div>
            <div style={s.passNum}>{p.passNumber ? `Pass #${p.passNumber}` : 'Pending Approval'}</div>
            <div style={s.route}>{p.from} → {p.to}</div>
            <div style={s.meta}>
              <span>Type: <strong>{p.passType}</strong></span>
              <span>Applied: {new Date(p.appliedAt).toLocaleDateString()}</span>
              {p.validFrom && <span>Valid: {new Date(p.validFrom).toLocaleDateString()} – {new Date(p.validTo).toLocaleDateString()}</span>}
            </div>
            {p.remarks && p.status === 'rejected' && <div style={s.remarks}>Reason: {p.remarks}</div>}
          </div>
          <div style={{ textAlign: 'right' }}>
            <div style={{ ...s.badge, background: statusColor[p.status] + '22', color: statusColor[p.status], marginBottom: 8 }}>{p.status.toUpperCase()}</div>
            {(p.status === 'approved' || p.status === 'expired') && (
              <button style={s.renewBtn} onClick={() => renew(p._id)}>Renew</button>
            )}
          </div>
        </div>
      ))}
    </div>
  );
}
